code = """import json\nimport re\n\nwith open(locals()[\'var_function-call-2241076992410809533\'], \'r\') as f:\n    civic_docs = json.load(f)\n\nprojects_data = []\n\n# Regex to find project names. Using r\"...\" for regex patterns to minimize escaping issues.\n# Project names typically start with a capital letter, can include letters, numbers, spaces, hyphens, ampersands, commas, dots, and single quotes.\n# They end with \' Project\' or \' Plan\'.\nproject_name_pattern = re.compile(r\"([A-Z][a-zA-Z0-9 \\\\-&,.'\\\\[\\\\]]+(?: Project| Plan))\")\n\nfor doc in civic_docs:\n    text = doc[\'text\']\n\n    # Find all potential project names in the document\n    for project_name_match in project_name_pattern.finditer(text):\n        project_name = project_name_match.group(1).strip()\n        \n        # Extract a context window around the project name to find status and confirm topic\n        start_idx = max(0, project_name_match.start() - 200)\n        end_idx = min(len(text), project_name_match.end() + 200)\n        context = text[start_idx:end_idx]\n\n        # Check if \'emergency\' or \'FEMA\' is in the project name or context\n        if re.search(r\"emergency|FEMA|Disaster Recovery\", project_name + context, re.IGNORECASE):\n            status = \"unknown\"\n            topic = \"general\"\n\n            if re.search(r\"Disaster Recovery\", context, re.IGNORECASE) or \'FEMA\' in project_name:\n                topic = \"disaster/FEMA/emergency\"\n            elif re.search(r\"emergency\", context, re.IGNORECASE) or \'emergency\' in project_name:\n                topic = \"emergency\"\n            elif re.search(r\"FEMA\", context, re.IGNORECASE):\n                topic = \"FEMA\"\n            else:\n                topic = \"capital/emergency/FEMA\" # Default if it\'s a CIP and mentions emergency/FEMA\n\n            # Infer status from context\n            if re.search(r\"completed|notice of completion\", context, re.IGNORECASE):\n                status = \"completed\"\n            elif re.search(r\"construction|under construction|begin construction|out to bid\", context, re.IGNORECASE):\n                status = \"construction\"\n            elif re.search(r\"design|preliminary design|FEMA/CalOES approval|consultant to finalize the design plans\", context, re.IGNORECASE):\n                status = \"design\"\n            elif re.search(r\"not started|identified in the .* Study|waiting for the agreement\", context, re.IGNORECASE):\n                status = \"not started\"\n            \n            projects_data.append({\"Project_Name\": project_name, \"status\": status, \"topic\": topic})\n\n    # Specific projects from hints if not caught by general pattern (within the loop for current document text)\n    # Outdoor Warning Signs\n    if re.search(r\"Outdoor Warning Signs\", text) and re.search(r\"emergency\", text, re.IGNORECASE):\n        projects_data.append({\"Project_Name\": \"Outdoor Warning Signs\", \"status\": \"design\", \"topic\": \"emergency\"})\n\n    # Latigo Canyon Road Retaining Wall Repair Project\n    if re.search(r\"Latigo Canyon Road Retaining Wall Repair Project\", text) and re.search(r\"FEMA/CalOES approval\", text):\n        projects_data.append({\"Project_Name\": \"Latigo Canyon Road Retaining Wall Repair Project\", \"status\": \"design\", \"topic\": \"FEMA\"})\n\n    # City Traffic Signals Backup Power\n    # Ensure backslashes are properly escaped in the regex.\n    # r\"...\" strings need \\\\ for literal \\. For (cid:190), it should be \\\\(cid:190\\\\)\n    traffic_signals_match = re.search(r\"City Traffic Signals Backup Power\\n\\n\\\\(cid:190\\\\) Project Description:(.*?)\\n\\n\\\\(cid:190\\\\) Updates:(.*?)\\n\\n\\\\(cid:190\\\\) Project Schedule:(.*?)(?=\\n\\n.+?$)\", text, re.DOTALL)\n    if traffic_signals_match:\n        description = traffic_signals_match.group(1)\n        updates = traffic_signals_match.group(2)\n        if re.search(r\"emergency\", description, re.IGNORECASE) or re.search(r\"emergency\", updates, re.IGNORECASE):\n            projects_data.append({\"Project_Name\": \"City Traffic Signals Backup Power\", \"status\": \"preliminary design\", \"topic\": \"emergency\"})\n\n\n# Remove duplicates\nunique_projects = []\nseen_projects = set()\nfor project in projects_data:\n    # Ensuring project_tuple is created correctly even if status or topic are not present (though they should be by now)\n    p_name = project.get(\'Project_Name\', \'\')\n    p_status = project.get(\'status\', \'\')\n    p_topic = project.get(\'topic\', \'\')\n    project_tuple = (p_name, p_status, p_topic)\n    \n    if project_tuple not in seen_projects:\n        unique_projects.append(project)\n        seen_projects.add(project_tuple)\n\nprint(\"__RESULT__:\")\nprint(json.dumps(unique_projects))"""

